422	}
423	
424	fn collect_subtree_hashes(node: tree_sitter::Node, source: &str, config: &LangConfig) -> Vec<u64> {
425	    let mut hashes = Vec::new();
426	    collect_hashes_recursive(node, source, config, &mut hashes);
427	    hashes.sort_unstable();
428	    hashes
429	}
430	
431	fn collect_hashes_recursive(
432	    node: tree_sitter::Node,
433	    source: &str,
434	    config: &LangConfig,
435	    hashes: &mut Vec<u64>,
436	) {
437	    let subtree = build_normalized_subtree(node, source, config);
438	    hashes.push(hash_str(&subtree));
439	    let mut cursor = node.walk();
440	    for child in node.children(&mut cursor) {
441	        collect_hashes_recursive(child, source, config, hashes);
442	    }
443	}
