131	pub fn find_duplicate_pairs(
132	    functions: &[FunctionInfo],
133	    threshold: f64,
134	    min_lines: usize,
135	    min_nodes: usize,
136	) -> Vec<DuplicatePair> {
137	    let candidates: Vec<&FunctionInfo> = functions
138	        .iter()
139	        .filter(|f| source_lines(f) >= min_lines && f.node_hashes.len() >= min_nodes)
140	        .collect();
141	
142	    let mut pairs: Vec<DuplicatePair> = Vec::new();
143	
144	    for i in 0..candidates.len() {
145	        for j in (i + 1)..candidates.len() {
146	            let a = candidates[i];
147	            let b = candidates[j];
148	            if is_same_location(a, b) {
149	                continue;
150	            }
151	            let score = jaccard(&a.node_hashes, &b.node_hashes);
152	            if score >= threshold {
153	                pairs.push(make_pair(a, b, score));
154	            }
155	        }
156	    }
157	
158	    pairs.sort_by(|a, b| {
159	        b.score
160	            .partial_cmp(&a.score)
161	            .unwrap_or(std::cmp::Ordering::Equal)
162	            .then_with(|| a.left.file.cmp(&b.left.file))
163	            .then_with(|| a.left.start_line.cmp(&b.left.start_line))
164	            .then_with(|| a.right.file.cmp(&b.right.file))
165	            .then_with(|| a.right.start_line.cmp(&b.right.start_line))
166	    });
167	
168	    pairs
169	}
