251	pub fn execute_cli(
252	    paths: &[String],
253	    format_str: &str,
254	    lang: Option<&str>,
255	    config: Config,
256	    run_fn: impl Fn(&[String], &Config) -> RunResult,
257	) -> CliResult {
258	    let format = match parse_output_format(format_str) {
259	        Ok(f) => f,
260	        Err(e) => return cli_error(e),
261	    };
262	
263	    let lang_val = if let Some(lang) = lang {
264	        match validate_lang(lang) {
265	            Ok(l) => Some(l),
266	            Err(e) => return cli_error(e),
267	        }
268	    } else {
269	        None
270	    };
271	
272	    let config = Config {
273	        format,
274	        lang: lang_val,
275	        ..config
276	    };
277	    let result = run_fn(paths, &config);
278	    run_result_to_cli(result, &config.format)
279	}
