1	use crate::ast::{LangConfig, extract_functions_with_config, lang_config, parse_source_tree_for};
2	use crate::core::{FunctionInfo, Lang};
3	use globset::{Glob, GlobSet, GlobSetBuilder};
4	use std::path::{Component, Path};
5	use std::process::Command;
6	use walkdir::WalkDir;
7	
8	const BUILTIN_EXCLUDED_DIRS: &[&str] = &[
9	    ".git",
10	    "target",
11	    "node_modules",
12	    "__pycache__",
13	    "vendor",
14	    "dist",
15	    ".next",
16	];
17	
18	pub fn is_builtin_excluded(path: &Path) -> bool {
19	    path.components().any(|c| {
20	        if let Component::Normal(name) = c {
21	            BUILTIN_EXCLUDED_DIRS.contains(&name.to_str().unwrap_or(""))
22	        } else {
23	            false
24	        }
25	    })
26	}
27	
28	fn git_check_ignore(path: &Path) -> Option<bool> {
29	    let abs = path.canonicalize().ok()?;
30	    let parent = abs.parent()?;
31	    let output = Command::new("git")
32	        .args([
33	            "-C",
34	            &parent.to_string_lossy(),
35	            "check-ignore",
36	            "--",
37	            &abs.to_string_lossy(),
38	        ])
39	        .output()
40	        .ok()?;
41	    Some(output.status.code() == Some(0))
42	}
43	
44	pub fn is_git_ignored(path: &Path) -> bool {
45	    git_check_ignore(path).unwrap_or(false)
46	}
47	
48	pub fn build_glob_set(patterns: &[String]) -> Result<GlobSet, globset::Error> {
49	    let mut builder = GlobSetBuilder::new();
50	    for pat in patterns {
51	        builder.add(Glob::new(pat)?);
52	    }
53	    builder.build()
54	}
55	
56	const EXT_LANG_MAP: &[(&str, Lang)] = &[
57	    ("rs", Lang::Rust),
58	    ("js", Lang::JavaScript),
59	    ("jsx", Lang::JavaScript),
60	    ("ts", Lang::TypeScript),
61	    ("tsx", Lang::Tsx),
62	    ("py", Lang::Python),
63	];
64	
65	pub fn detect_lang(path: &Path) -> Option<Lang> {
66	    let ext = path.extension().and_then(|e| e.to_str())?;
67	    EXT_LANG_MAP
68	        .iter()
69	        .find(|(e, _)| *e == ext)
70	        .map(|(_, l)| *l)
71	}
72	
73	pub fn is_rust_file(path: &Path) -> bool {
74	    path.extension().and_then(|e| e.to_str()) == Some("rs")
75	}
76	
77	pub fn is_supported_file(path: &Path) -> bool {
78	    detect_lang(path).is_some()
79	}
80	
81	pub fn should_skip(path: &Path, exclude_set: &GlobSet) -> bool {
82	    if exclude_set.is_empty() {
83	        return false;
84	    }
85	    exclude_set.is_match(path)
86	}
87	
88	/// Returns whether a file should be scanned.
89	/// When force_lang is Some, every non-excluded, non-builtin-excluded file is scanned.
90	/// When force_lang is None, only files with recognized extensions are scanned.
91	pub fn should_scan_file(
92	    path: &Path,
93	    exclude_set: &GlobSet,
94	    git_ignored: &dyn Fn(&Path) -> bool,
95	    force_lang: Option<Lang>,
96	) -> bool {
97	    if is_builtin_excluded(path) || should_skip(path, exclude_set) || git_ignored(path) {
98	        return false;
99	    }
100	    match force_lang {
101	        Some(_) => true,
102	        None => is_supported_file(path),
103	    }
104	}
105	
106	pub fn collect_all_functions(
107	    paths: &[String],
108	    exclude_set: &GlobSet,
109	    force_lang: Option<Lang>,
110	) -> (Vec<FunctionInfo>, Vec<String>) {
111	    let mut functions: Vec<FunctionInfo> = Vec::new();
112	    let mut errors: Vec<String> = Vec::new();
113	    for path_str in paths {
114	        let path = Path::new(path_str);
115	        if !path.exists() {
116	            errors.push(format!("path does not exist: {}", path_str));
117	        } else {
118	            collect_functions_from_path(path, exclude_set, force_lang, &mut functions, &mut errors);
119	        }
120	    }
121	    (functions, errors)
122	}
123	
124	pub fn collect_functions_from_path(
125	    path: &Path,
126	    exclude_set: &GlobSet,
127	    force_lang: Option<Lang>,
128	    functions: &mut Vec<FunctionInfo>,
129	    errors: &mut Vec<String>,
130	) {
131	    if path.is_file() {
132	        collect_from_single_file(path, exclude_set, force_lang, functions, errors);
133	    } else {
134	        collect_from_directory(path, exclude_set, force_lang, functions, errors);
135	    }
136	}
137	
138	pub fn collect_from_single_file(
139	    path: &Path,
140	    exclude_set: &GlobSet,
141	    force_lang: Option<Lang>,
142	    functions: &mut Vec<FunctionInfo>,
143	    errors: &mut Vec<String>,
144	) {
145	    if should_scan_file(path, exclude_set, &is_git_ignored, force_lang) {
146	        let lang = force_lang.or_else(|| detect_lang(path)).unwrap();
147	        process_file(path, lang, functions, errors);
148	    }
149	}
150	
151	fn process_entry(
152	    entry: Result<walkdir::DirEntry, walkdir::Error>,
153	    exclude_set: &GlobSet,
154	    force_lang: Option<Lang>,
155	    functions: &mut Vec<FunctionInfo>,
156	    errors: &mut Vec<String>,
157	) {
158	    match entry {
159	        Ok(e)
160	            if e.file_type().is_file()
161	                && should_scan_file(e.path(), exclude_set, &is_git_ignored, force_lang) =>
162	        {
163	            let lang = force_lang.or_else(|| detect_lang(e.path())).unwrap();
164	            process_file(e.path(), lang, functions, errors);
165	        }
166	        Ok(_) => {}
167	        Err(err) => errors.push(format!("walk error: {}", err)),
168	    }
169	}
170	
171	pub fn collect_from_directory(
172	    path: &Path,
173	    exclude_set: &GlobSet,
174	    force_lang: Option<Lang>,
175	    functions: &mut Vec<FunctionInfo>,
176	    errors: &mut Vec<String>,
177	) {
178	    let walker = WalkDir::new(path)
179	        .sort_by_file_name()
180	        .into_iter()
181	        .filter_entry(|e| !e.file_type().is_dir() || !is_builtin_excluded(e.path()));
182	    for entry in walker {
183	        process_entry(entry, exclude_set, force_lang, functions, errors);
184	    }
185	}
186	
187	pub fn process_file(
188	    path: &Path,
189	    lang: Lang,
190	    functions: &mut Vec<FunctionInfo>,
191	    errors: &mut Vec<String>,
192	) {
193	    let source = match std::fs::read_to_string(path) {
194	        Ok(s) => s,
195	        Err(e) => {
196	            errors.push(format!("cannot read {}: {}", path.display(), e));
197	            return;
198	        }
199	    };
200	
201	    let config: &LangConfig = lang_config(lang);
202	    match parse_source_tree_for(&source, lang) {
203	        Ok(tree) => {
204	            let file_str = path.to_string_lossy().to_string();
205	            extract_functions_with_config(tree.root_node(), &source, &file_str, config, functions);
206	        }
207	        Err(msg) => {
208	            errors.push(format!("{} in {}", msg, path.display()));
209	        }
210	    }
211	}
