1	use drywall::scan::{
2	    build_glob_set, detect_lang, is_builtin_excluded, is_rust_file, should_scan_file, should_skip,
3	};
4	use proptest::prelude::*;
5	use std::path::Path;
6	
7	const BUILTIN_DIRS: &[&str] = &[
8	    ".git",
9	    "target",
10	    "node_modules",
11	    "__pycache__",
12	    "vendor",
13	    "dist",
14	    ".next",
15	];
16	
17	fn builtin_dir() -> impl Strategy<Value = &'static str> {
18	    proptest::sample::select(BUILTIN_DIRS)
19	}
20	
21	fn safe_segment() -> impl Strategy<Value = String> {
22	    "[a-z][a-z0-9_]{0,8}".prop_map(|s| s)
23	}
24	
25	proptest! {
26	    // --- is_builtin_excluded invariants ---
27	
28	    #[test]
29	    fn builtin_excluded_any_segment_position(
30	        prefix in prop::collection::vec(safe_segment(), 0..3),
31	        excluded in builtin_dir(),
32	        suffix in prop::collection::vec(safe_segment(), 0..3),
33	    ) {
34	        let mut parts = prefix;
35	        parts.push(excluded.to_string());
36	        parts.extend(suffix);
37	        parts.push("file.rs".to_string());
38	        let path = parts.join("/");
39	        prop_assert!(
40	            is_builtin_excluded(Path::new(&path)),
41	            "expected excluded for path: {}",
42	            path
43	        );
44	    }
45	
46	    #[test]
47	    fn non_builtin_segments_not_excluded(
48	        segments in prop::collection::vec(safe_segment(), 1..4),
49	    ) {
50	        let mut path_parts = segments.clone();
51	        path_parts.push("file.rs".to_string());
52	        let path = path_parts.join("/");
53	        // Only paths with no builtin segment should pass
54	        let has_builtin = segments.iter().any(|s| BUILTIN_DIRS.contains(&s.as_str()));
55	        if !has_builtin {
56	            prop_assert!(
57	                !is_builtin_excluded(Path::new(&path)),
58	                "expected non-excluded for path: {}",
59	                path
60	            );
61	        }
62	    }
63	
64	    #[test]
65	    fn partial_name_match_not_excluded(
66	        excluded in builtin_dir(),
67	        suffix in "[a-z]{1,4}",
68	    ) {
69	        let segment = format!("{}{}", excluded, suffix);
70	        let path = format!("{}/file.rs", segment);
71	        prop_assert!(
72	            !is_builtin_excluded(Path::new(&path)),
73	            "partial name '{}' must not be excluded",
74	            segment
75	        );
76	    }
77	
78	    // --- is_rust_file invariant ---
79	
80	    #[test]
81	    fn is_rust_file_iff_rs_extension(
82	        stem in "[a-z][a-z0-9_]{0,10}",
83	        ext in "[a-z]{1,4}",
84	    ) {
85	        let path = format!("{}.{}", stem, ext);
86	        let result = is_rust_file(Path::new(&path));
87	        if ext == "rs" {
88	            prop_assert!(result, "expected .rs file to be rust: {}", path);
89	        } else {
90	            prop_assert!(!result, "expected non-.rs file to not be rust: {}", path);
91	        }
92	    }
93	
94	    // --- should_skip (glob) invariants ---
95	
96	    #[test]
97	    fn should_skip_empty_set_never_skips(path in "[a-z/]{1,20}\\.rs") {
98	        let gs = build_glob_set(&[]).unwrap();
99	        prop_assert!(!should_skip(Path::new(&path), &gs));
100	    }
101	
102	    #[test]
103	    fn should_skip_matching_pattern_skips(stem in "[a-z][a-z0-9_]{0,8}") {
104	        let path = format!("acceptance/{}.rs", stem);
105	        let gs = build_glob_set(&["acceptance/**".to_string()]).unwrap();
106	        prop_assert!(
107	            should_skip(Path::new(&path), &gs),
108	            "expected acceptance path to be skipped: {}",
109	            path
110	        );
111	    }
112	
113	    #[test]
