1	// Mutation hardening tests — separate from unit and acceptance suites.
2	// Each test targets a specific surviving mutant identified by cargo-mutants.
3	
4	use drywall::ast::{
5	    JS_CONFIG, RUST_CONFIG, build_normalized_subtree, extract_functions,
6	    extract_functions_with_config, extract_let_declaration, make_parser, make_parser_for,
7	};
8	use drywall::scan::{build_glob_set, collect_from_directory};
9	use drywall::{FunctionInfo, Lang, find_duplicate_pairs, jaccard, source_lines};
10	use std::fs;
11	
12	fn parse_and_extract(source: &str) -> Vec<FunctionInfo> {
13	    let tree = make_parser().parse(source, None).unwrap();
14	    let mut functions = Vec::new();
15	    extract_functions(tree.root_node(), source, "test.rs", &mut functions);
16	    functions
17	}
18	
19	fn make_fi(start_line: usize, end_line: usize, hashes: Vec<u64>) -> FunctionInfo {
20	    FunctionInfo {
21	        file: "test.rs".to_string(),
22	        start_line,
23	        end_line,
24	        node_hashes: hashes,
25	    }
26	}
27	
28	// --- ast.rs:55 --- extract_let_declaration: child.kind() != "closure_expression"
29	// Mutant: replace != with ==
30	// Guard: a closure containing a nested closure must yield only 1 entry (the outer let-bound
31	// closure). If != became ==, we'd recurse INTO the outer closure's children, potentially
32	// finding and registering the inner closure as a second function. Verify we do NOT double-count.
33	#[test]
34	fn let_decl_nested_closure_not_double_counted() {
35	    // A let with a closure that itself contains another let-bound closure inside its body.
36	    // With != mutated to ==: we'd recurse into the outer closure_expression, find the inner
37	    // let_declaration, and push a second function entry.
38	    let source = "let outer = |x: i32| -> i32 { let inner = |y: i32| y + 1; inner(x) };\n";
39	    let tree = make_parser().parse(source, None).unwrap();
40	    let mut functions = Vec::new();
41	    let root = tree.root_node();
42	    let mut cursor = root.walk();
43	    let children: Vec<_> = root.children(&mut cursor).collect();
44	    if let Some(let_node) = children.iter().find(|n| n.kind() == "let_declaration") {
45	        extract_let_declaration(*let_node, source, "test.rs", &mut functions);
46	    }
47	    assert_eq!(
48	        functions.len(),
49	        1,
50	        "only the outer closure should be captured, got {} entries",
51	        functions.len()
52	    );
53	}
54	
55	// Verify that non-closure let children ARE traversed (extract nested fn items from sub-nodes).
56	#[test]
57	fn let_decl_non_closure_children_are_traversed() {
58	    // A plain let that contains no closure; the extract_let_declaration should not add anything,
59	    // but it must not prevent traversal of other children.
60	    let source = "let x = 42;\n";
61	    let tree = make_parser().parse(source, None).unwrap();
62	    let mut functions = Vec::new();
63	    let root = tree.root_node();
64	    let mut cursor = root.walk();
65	    let children: Vec<_> = root.children(&mut cursor).collect();
66	    if let Some(let_node) = children.iter().find(|n| n.kind() == "let_declaration") {
67	        extract_let_declaration(*let_node, source, "test.rs", &mut functions);
68	    }
69	    assert_eq!(functions.len(), 0);
70	}
71	
72	// --- ast.rs:34 --- delete match arm "let_declaration" in extract_functions
73	// Mutant: if the let_declaration arm is deleted, extract_functions falls to the _ arm which
74	// recurses into children — but never calls extract_let_declaration, so let-bound closures
75	// are never captured as functions.
76	#[test]
77	fn extract_functions_captures_let_bound_closure() {
78	    // extract_functions must find the closure in a top-level let statement.
79	    // If the let_declaration arm is deleted, the closure is never pushed.
80	    let source = "let f = |x: i32| -> i32 { x + 1 };\n";
81	    let functions = parse_and_extract(source);
82	    assert_eq!(
83	        functions.len(),
84	        1,
85	        "let-bound closure must be captured by extract_functions, got {}",
86	        functions.len()
87	    );
88	}
89	
90	// --- ast.rs:75 --- make_function_info: start_line = row + 1 (mutation: + -> *)
91	// Guard: tree-sitter rows are 0-based; +1 makes them 1-based. For a top-level function on row 0,
92	// start_line must be 1 (not 0, which * would produce: 0*1=0).
93	#[test]
94	fn make_function_info_start_line_is_one_based() {
95	    let source = "fn top() {}\n";
96	    let functions = parse_and_extract(source);
97	    assert_eq!(functions.len(), 1);
98	    assert_eq!(
99	        functions[0].start_line, 1,
100	        "start_line must be 1-based (row 0 + 1), got {}",
101	        functions[0].start_line
102	    );
103	}
104	
105	// For a function on row 2 (third line), start_line must be 3, not 6 (which * would give: 2*3=6).
106	#[test]
107	fn make_function_info_start_line_correct_for_non_zero_row() {
108	    let source = "\n\nfn third_row() {}\n";
109	    let functions = parse_and_extract(source);
110	    assert_eq!(functions.len(), 1);
111	    assert_eq!(
112	        functions[0].start_line, 3,
113	        "start_line for row 2 must be 3 (2+1), got {}",
114	        functions[0].start_line
115	    );
116	}
117	
118	// --- ast.rs:89 --- normalize_node_text: literal match arm deletion
119	// Guard: integer/float/string/char/bool literals must normalize to _LIT so that structurally
120	// identical functions with different literal values still get high Jaccard scores.
121	#[test]
122	fn normalize_literal_integers_are_replaced() {
123	    // Two functions differing only in integer literals must have the same normalized subtree hash.
124	    let source_a = "fn a() -> i32 { 42 }\n";
125	    let source_b = "fn b() -> i32 { 99 }\n";
126	    let tree_a = make_parser().parse(source_a, None).unwrap();
127	    let tree_b = make_parser().parse(source_b, None).unwrap();
128	    let norm_a = build_normalized_subtree(tree_a.root_node(), source_a, &RUST_CONFIG);
129	    let norm_b = build_normalized_subtree(tree_b.root_node(), source_b, &RUST_CONFIG);
130	    assert_eq!(
131	        norm_a, norm_b,
132	        "functions differing only in integer literals must normalize identically"
133	    );
134	}
135	
136	#[test]
137	fn normalize_float_literals_are_replaced() {
138	    // float_literal is a leaf in tree-sitter-rust (like integer_literal).
139	    let source_a = "fn a() -> f64 { 1.5 }\n";
140	    let source_b = "fn b() -> f64 { 9.9 }\n";
141	    let tree_a = make_parser().parse(source_a, None).unwrap();
